import{_ as e,o as l,c as a,a2 as s}from"./chunks/framework.D36jym0Z.js";const x=JSON.parse('{"title":"Host Compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"hosts/compatibility.md","filePath":"hosts/compatibility.md","lastUpdated":1784629191000}'),i={name:"hosts/compatibility.md"};function d(n,t,o,r,f,y){return l(),a("div",null,[...t[0]||(t[0]=[s('<h1 id="host-compatibility" tabindex="-1">Host Compatibility <a class="header-anchor" href="#host-compatibility" aria-label="Permalink to &quot;Host Compatibility&quot;">​</a></h1><p>LightMem2 supports three agent hosts. Each host has a different integration style, but the plugin behavior is consistent across all of them.</p><h2 id="supported-hosts" tabindex="-1">Supported Hosts <a class="header-anchor" href="#supported-hosts" aria-label="Permalink to &quot;Supported Hosts&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Host</th><th style="text-align:left;">Integration</th><th style="text-align:left;">Adapter Location</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="./openclaw">OpenClaw</a></td><td style="text-align:left;">Native plugin slot</td><td style="text-align:left;"><code>components/adapters/openclaw/</code></td></tr><tr><td style="text-align:left;"><a href="./codex">Codex CLI</a></td><td style="text-align:left;">Local proxy + hooks</td><td style="text-align:left;"><code>components/adapters/codex/</code></td></tr><tr><td style="text-align:left;"><a href="./claude-code">Claude Code</a></td><td style="text-align:left;">Local gateway + MCP</td><td style="text-align:left;"><code>components/adapters/claude-code/</code></td></tr></tbody></table><h2 id="feature-matrix" tabindex="-1">Feature Matrix <a class="header-anchor" href="#feature-matrix" aria-label="Permalink to &quot;Feature Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Feature</th><th style="text-align:left;">OpenClaw</th><th style="text-align:left;">Codex</th><th style="text-align:left;">Claude Code</th></tr></thead><tbody><tr><td style="text-align:left;">Stable Prefix</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Context Reduction</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Context Eviction</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Visual Inspector</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Session Reports</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">In-session Commands</td><td style="text-align:left;">✅ (<code>/lightmem2</code>)</td><td style="text-align:left;">— (standalone CLI)</td><td style="text-align:left;">— (standalone CLI)</td></tr><tr><td style="text-align:left;">Standalone CLI</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">MCP Recovery Server</td><td style="text-align:left;">—</td><td style="text-align:left;">✅</td><td style="text-align:left;">✅</td></tr><tr><td style="text-align:left;">Auto-start Proxy</td><td style="text-align:left;">✅ (gateway restart)</td><td style="text-align:left;">✅ (SessionStart hook)</td><td style="text-align:left;">✅ (SessionStart hook)</td></tr></tbody></table><h2 id="choosing-a-host" tabindex="-1">Choosing a Host <a class="header-anchor" href="#choosing-a-host" aria-label="Permalink to &quot;Choosing a Host&quot;">​</a></h2><ul><li><strong>OpenClaw</strong>: Best integration experience — native plugin slot, in-session commands, gateway-level restart.</li><li><strong>Codex CLI</strong>: Full feature parity via standalone CLI + hooks. Proxy starts on first session.</li><li><strong>Claude Code</strong>: Full feature parity via standalone CLI + gateway + MCP. Gateway starts on first session.</li></ul><p>Plugin behavior (stabilizer, reduction, eviction) is identical regardless of host. The only difference is how you interact with TokenPilot — in-session commands vs. standalone CLI.</p><h2 id="test-environment" tabindex="-1">Test Environment <a class="header-anchor" href="#test-environment" aria-label="Permalink to &quot;Test Environment&quot;">​</a></h2><p>All host pages include the test environment and last verification date.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Host</th><th style="text-align:left;">Last verified</th></tr></thead><tbody><tr><td style="text-align:left;">OpenClaw</td><td style="text-align:left;">2026-07-16</td></tr><tr><td style="text-align:left;">Codex</td><td style="text-align:left;">2026-07-16</td></tr><tr><td style="text-align:left;">Claude Code</td><td style="text-align:left;">2026-07-16</td></tr></tbody></table>',12)])])}const g=e(i,[["render",d]]);export{x as __pageData,g as default};
